 namespace WPAICG\Chat\Frontend\Shortcode; use WPAICG\aipkit_dashboard; use WPAICG\Chat\Storage\BotStorage; use WPAICG\Chat\Storage\BotSettingsManager; require_once __DIR__ . '/featuremanager/methods.php'; if (!defined('ABSPATH')) { exit; } class FeatureManager { public static function determine_flags(array $settings): array { $flags = []; $core_flags = FeatureManagerMethods\get_core_flag_values_logic($settings); $flags = array_merge($flags, [ 'popup_enabled' => $core_flags['popup_enabled'], 'enable_fullscreen' => $core_flags['enable_fullscreen'], 'enable_download' => $core_flags['enable_download'], 'enable_copy_button' => $core_flags['enable_copy_button'], 'enable_feedback' => $core_flags['enable_feedback'], 'enable_voice_input_ui' => $core_flags['enable_voice_input_ui'], ]); $flags['feedback_ui_enabled'] = $flags['enable_feedback']; $is_pro_plan = class_exists(aipkit_dashboard::class) ? aipkit_dashboard::is_pro_plan() : false; $ui_flags = FeatureManagerMethods\get_ui_flags_logic($core_flags, $is_pro_plan); $flags = array_merge($flags, $ui_flags); $upload_flags = FeatureManagerMethods\get_upload_flags_logic($core_flags); $flags = array_merge($flags, $upload_flags); $web_search_flag = FeatureManagerMethods\get_web_search_flag_logic( $settings, $core_flags['allow_openai_web_search_tool_setting'], $core_flags['allow_claude_web_search_tool_setting'], $core_flags['allow_openrouter_web_search_tool_setting'], $core_flags['allow_xai_web_search_tool_setting'] ); $flags = array_merge($flags, $web_search_flag); $google_grounding_flags = FeatureManagerMethods\get_google_grounding_flags_logic($settings, $core_flags['allow_google_search_grounding_setting']); $flags = array_merge($flags, $google_grounding_flags); $realtime_voice_flag = FeatureManagerMethods\get_realtime_voice_flag_logic($core_flags); $flags = array_merge($flags, $realtime_voice_flag); $derived_flags = FeatureManagerMethods\compute_derived_flags_logic($flags); $flags = array_merge($flags, $derived_flags); return $flags; } } 